"""Comprehensive end-to-end tests for all auto-generated agent API endpoints.

Tests every endpoint generated by ``create_default_router``:
  POST  /invoke                      sync invocation
  POST  /invoke/stream               SSE streaming
  POST  /chat                        session-aware chat
  GET   /health                      per-agent health
  GET   /config                      agent configuration
  GET   /prompts                     prompt versions
  GET   /card                        A2A agent card
  POST  /a2a/tasks                   A2A task submission
  GET   /a2a/tasks/{id}              A2A task status
  POST  /a2a/tasks/{id}/cancel       cancel A2A task
  POST  /threads                     create thread
  GET   /threads                     list threads
  GET   /threads/{id}                get thread
  PATCH /threads/{id}                update thread
  DELETE /threads/{id}               delete thread
  GET   /threads/{id}/messages       get messages
  DELETE /threads/{id}/messages      clear messages
  GET   /threads/{id}/summary        thread summary
  POST  /optimize/invoke             optimization invocation
  POST  /feedback                    submit feedback
  GET   /feedback                    list feedback
  GET   /feedback/export             export feedback as JSONL

Also covers:
  - Both functional agents (node_fn/graph_fn) and class agents (BaseGraphAgent)
  - Error cases: 404 for missing agent, 500 for agent failure, 422 for bad input
  - SSE protocol: chunked data frames, [DONE] sentinel, error frames
  - Chat with thread_id and history
  - A2A: synchronous fallback (no task manager) and async (with task manager)
  - Thread CRUD full lifecycle
  - Platform-level: /health, /readiness, /agents, /.well-known/agent.json
"""

from __future__ import annotations

import json
from dataclasses import dataclass, field
from typing import Any

import pytest
from fastapi.testclient import TestClient

from agentomatic import AgentManifest, AgentPlatform
from agentomatic.agents import BaseGraphAgent
from agentomatic.storage.memory import MemoryStore

# ===========================================================================
# Test agents
# ===========================================================================


@dataclass
class _EchoState:
    request: str = ""
    output: dict[str, Any] = field(default_factory=dict)


class _ClassEchoAgent(BaseGraphAgent[_EchoState]):
    """BaseGraphAgent subclass — exercises the dataclass-state path."""

    agent_name = "class_echo"
    agent_description = "Class-based echo agent"
    agent_framework = "graph_agent"

    def build_graph(self) -> Any:
        g = self.new_graph()
        g.add_node("respond", self.respond)
        g.set_entry_point("respond")
        g.set_finish_point("respond")
        return g.compile()

    def respond(self, state: _EchoState) -> _EchoState:
        state.output = {
            "response": f"Class:{state.request}",
            "agent_type": "class-echo",
            "steps_taken": ["respond"],
        }
        return state

    def input_to_state(self, d: dict[str, Any]) -> _EchoState:
        return _EchoState(request=d.get("current_query", d.get("query", "")))

    def state_to_output(self, state: _EchoState) -> dict[str, Any]:
        return state.output


async def _echo_fn(state: dict[str, Any]) -> dict[str, Any]:
    """Functional agent: echoes query."""
    return {
        "response": f"Fn:{state.get('current_query', '')}",
        "agent_type": "fn-echo",
        "suggestions": ["try again"],
        "steps_taken": ["echo"],
        "citations": [{"source": "test"}],
        "metadata": {"fn": True},
    }


async def _fail_fn(state: dict[str, Any]) -> dict[str, Any]:
    raise RuntimeError("intended failure")


# ===========================================================================
# Platform fixtures
# ===========================================================================


def _build_platform(store: MemoryStore | None = None) -> AgentPlatform:
    p = AgentPlatform(
        agents_dir="/tmp/agentomatic_ep_test",
        title="EP Test",
        version="0.0.1",
        store=store,
        enable_studio=True,
    )
    # Functional echo agent
    p.register_agent(
        manifest=AgentManifest(
            name="echo",
            slug="fn-echo",
            description="Functional echo agent",
            version="1.0.0",
            intent_keywords=["echo"],
        ),
        node_fn=_echo_fn,
    )
    # Failing agent
    p.register_agent(
        manifest=AgentManifest(name="failer", slug="fn-failer", description="Always fails"),
        node_fn=_fail_fn,
    )
    # Class agent
    reg = _ClassEchoAgent().as_registered_agent()
    p.register_agent(
        manifest=reg.manifest,
        node_fn=reg.node_fn,
        graph_fn=reg.graph_fn,
        class_instance=reg.class_instance,
    )
    return p


@pytest.fixture
def store() -> MemoryStore:
    return MemoryStore()


@pytest.fixture
def client(store) -> Any:
    p = _build_platform(store=store)
    with TestClient(p.build()) as c:
        yield c


@pytest.fixture
def client_no_store() -> Any:
    p = _build_platform(store=None)
    with TestClient(p.build()) as c:
        yield c


# ===========================================================================
# Helpers
# ===========================================================================

BASE = "/api/v1"


def _invoke(client, name: str, query: str = "hello", **extra) -> Any:
    return client.post(f"{BASE}/{name}/invoke", json={"query": query, **extra})


def _stream_lines(client, name: str, query: str = "hello") -> list[str]:
    """Parse SSE stream into a list of data lines (stripped)."""
    resp = client.post(f"{BASE}/{name}/invoke/stream", json={"query": query})
    assert resp.status_code == 200, resp.text
    return [
        line[len("data: ") :].strip()
        for line in resp.text.splitlines()
        if line.startswith("data: ")
    ]


