class TestPlatformEndpoints:
    def test_root_200(self, client):
        r = client.get("/")
        assert r.status_code == 200

    def test_docs_200(self, client):
        r = client.get("/docs")
        assert r.status_code == 200

    def test_openapi_json(self, client):
        r = client.get("/openapi.json")
        assert r.status_code == 200
        assert "paths" in r.json()

    def test_health_aggregated(self, client):
        r = client.get("/health")
        assert r.status_code == 200
        data = r.json()
        assert "status" in data or "agents" in data

    def test_readiness(self, client):
        r = client.get("/readiness")
        assert r.status_code in (200, 404)  # 404 if endpoint not mounted

    def test_agents_listing(self, client):
        r = client.get(f"{BASE}/agents")
        assert r.status_code == 200
        body = r.json()
        # Response shape: {"agents": {"<name>": {...}, ...}}
        agents_section = body.get("agents", body) if isinstance(body, dict) else {}
        if isinstance(agents_section, dict):
            # Keyed by agent name
            all_names = list(agents_section.keys())
        else:
            # List of agent dicts
            all_names = [a.get("name", a.get("slug", "")) for a in agents_section]
        assert any("echo" in n for n in all_names)

    def test_well_known_agent_json(self, client):
        r = client.get("/.well-known/agent.json")
        assert r.status_code == 200


