class TestInvokeSync:
    def test_functional_agent_returns_200(self, client):
        r = _invoke(client, "echo", "world")
        assert r.status_code == 200
        data = r.json()
        assert data["response"] == "Fn:world"
        assert data["agent_type"] == "fn-echo"

    def test_response_fields_present(self, client):
        r = _invoke(client, "echo")
        data = r.json()
        for fname in ("response", "agent_type", "duration_ms", "metadata"):
            assert fname in data, f"missing field: {fname}"

    def test_duration_ms_positive(self, client):
        r = _invoke(client, "echo")
        assert r.json()["duration_ms"] >= 0.0

    def test_empty_query_still_200(self, client):
        r = _invoke(client, "echo", "")
        assert r.status_code == 200

    def test_missing_agent_404(self, client):
        r = _invoke(client, "does_not_exist")
        assert r.status_code == 404

    def test_failing_agent_500(self, client):
        r = _invoke(client, "failer")
        assert r.status_code == 500

    def test_class_agent_invoke(self, client):
        r = _invoke(client, "class_echo", "ping")
        assert r.status_code == 200
        assert r.json()["response"] == "Class:ping"

    def test_extra_fields_passed_through(self, client):
        r = client.post(
            f"{BASE}/echo/invoke",
            json={
                "query": "hi",
                "user_id": "tester",
                "prompt_version": "v1",
            },
        )
        assert r.status_code == 200

    def test_query_alias_current_query(self, client):
        """Class agents receive current_query through input_to_state."""
        # The HTTP schema always expects 'query'; the class agent's input_to_state
        # maps it to 'current_query' internally.
        r = client.post(f"{BASE}/class_echo/invoke", json={"query": "via_cq"})
        assert r.status_code == 200
        assert "via_cq" in r.json()["response"]


# ===========================================================================
# 3. POST /invoke/stream — SSE
# ===========================================================================


class TestInvokeStream:
    def test_status_200(self, client):
        r = client.post(f"{BASE}/echo/invoke/stream", json={"query": "stream"})
        assert r.status_code == 200

    def test_content_type_event_stream(self, client):
        r = client.post(f"{BASE}/echo/invoke/stream", json={"query": "ct"})
        assert "text/event-stream" in r.headers.get("content-type", "")

    def test_done_sentinel_present(self, client):
        lines = _stream_lines(client, "echo")
        assert "[DONE]" in lines

    def test_response_data_frame_present(self, client):
        lines = _stream_lines(client, "echo", "hello")
        # At least one data frame is not [DONE]
        frames = [ln for ln in lines if ln != "[DONE]"]
        assert len(frames) >= 1

    def test_response_payload_parseable(self, client):
        lines = _stream_lines(client, "echo", "parseable")
        frames = [ln for ln in lines if ln and ln != "[DONE]"]
        assert len(frames) >= 1
        first = json.loads(frames[0])
        assert isinstance(first, dict)
        assert "response" in first

    def test_class_agent_stream(self, client):
        lines = _stream_lines(client, "class_echo", "streamed")
        assert "[DONE]" in lines
        frames = [ln for ln in lines if ln and ln != "[DONE]"]
        # Class agents may emit per-node frames before the final payload.
        payloads = [json.loads(ln) for ln in frames]
        finals = [p for p in payloads if isinstance(p, dict) and "response" in p]
        assert finals
        assert finals[-1]["response"] == "Class:streamed"

    def test_failing_agent_stream_returns_error_frame(self, client):
        r = client.post(f"{BASE}/failer/invoke/stream", json={"query": "fail"})
        assert r.status_code == 200
        lines = _stream_lines(client, "failer", "fail")
        # Must emit an error frame (not a 500)
        error_frames = [ln for ln in lines if "error" in ln.lower()]
        assert len(error_frames) >= 1

    def test_x_agent_header(self, client):
        r = client.post(f"{BASE}/echo/invoke/stream", json={"query": "hdr"})
        assert r.headers.get("x-agent") == "echo"

    def test_missing_agent_stream_returns_done_or_error(self, client):
        r = client.post(f"{BASE}/ghost/invoke/stream", json={"query": "q"})
        # Either a 404 or an error SSE frame — both acceptable
        assert r.status_code in (200, 404)


