# 9. POST /a2a/tasks — A2A task lifecycle
# ===========================================================================


class TestA2ATasks:
    def _submit(self, client, content="A2A query", name="echo") -> dict:
        r = client.post(
            f"{BASE}/{name}/a2a/tasks",
            json={
                "message": {"content": content},
                "metadata": {},
            },
        )
        assert r.status_code == 200, r.text
        return r.json()

    def test_submit_returns_task_id(self, client):
        data = self._submit(client)
        assert "task_id" in data

    def test_submit_returns_status(self, client):
        data = self._submit(client)
        assert "status" in data

    def test_synchronous_fallback_has_result(self, client):
        """Without a task manager, A2A runs synchronously and result is inline."""
        data = self._submit(client)
        # Sync fallback: task completed inline
        if data.get("status") in ("completed", "succeeded"):
            assert "result" in data or "artifacts" in data

    def test_get_task_status(self, client):
        data = self._submit(client)
        task_id = data["task_id"]
        r = client.get(f"{BASE}/echo/a2a/tasks/{task_id}")
        # Either 200 (task store) or 404 (no task store, sync mode)
        assert r.status_code in (200, 404)

    def test_cancel_task(self, client):
        data = self._submit(client)
        task_id = data["task_id"]
        r = client.post(f"{BASE}/echo/a2a/tasks/{task_id}/cancel")
        assert r.status_code in (200, 404, 409)  # 409 if already completed

    def test_unknown_task_404(self, client):
        r = client.get(f"{BASE}/echo/a2a/tasks/nonexistent-id-12345")
        assert r.status_code == 404

    def test_class_agent_a2a(self, client):
        data = self._submit(client, name="class_echo", content="a2a class")
        assert "task_id" in data


