class TestThreads:
    def test_list_threads_empty(self, client):
        r = client.get(f"{BASE}/echo/threads")
        assert r.status_code == 200
        data = r.json()
        assert "threads" in data or isinstance(data, list)

    def test_create_thread(self, client):
        r = client.post(
            f"{BASE}/echo/threads",
            json={
                "user_id": "user1",
                "title": "Test Thread",
            },
        )
        assert r.status_code == 200
        data = r.json()
        assert "thread_id" in data or "id" in data

    def test_get_thread(self, client):
        # Create first
        cr = client.post(f"{BASE}/echo/threads", json={"user_id": "u", "title": "T"})
        assert cr.status_code == 200
        tid = cr.json().get("thread_id") or cr.json().get("id", "")
        if tid:
            r = client.get(f"{BASE}/echo/threads/{tid}")
            assert r.status_code == 200

    def test_update_thread(self, client):
        cr = client.post(f"{BASE}/echo/threads", json={"user_id": "u", "title": "Old"})
        assert cr.status_code == 200
        tid = cr.json().get("thread_id") or cr.json().get("id", "")
        if tid:
            r = client.patch(f"{BASE}/echo/threads/{tid}", json={"title": "New"})
            assert r.status_code == 200

    def test_get_messages_empty(self, client):
        cr = client.post(f"{BASE}/echo/threads", json={"user_id": "u", "title": "T"})
        tid = cr.json().get("thread_id") or cr.json().get("id", "")
        if tid:
            r = client.get(f"{BASE}/echo/threads/{tid}/messages")
            assert r.status_code == 200
            data = r.json()
            assert "messages" in data or isinstance(data, list)

    def test_delete_thread(self, client):
        cr = client.post(f"{BASE}/echo/threads", json={"user_id": "u", "title": "Del"})
        tid = cr.json().get("thread_id") or cr.json().get("id", "")
        if tid:
            r = client.delete(f"{BASE}/echo/threads/{tid}")
            assert r.status_code == 200

    def test_clear_thread_messages(self, client):
        cr = client.post(f"{BASE}/echo/threads", json={"user_id": "u", "title": "Clr"})
        tid = cr.json().get("thread_id") or cr.json().get("id", "")
        if tid:
            r = client.delete(f"{BASE}/echo/threads/{tid}/messages")
            assert r.status_code == 200

    def test_thread_summary(self, client):
        cr = client.post(f"{BASE}/echo/threads", json={"user_id": "u", "title": "Sum"})
        tid = cr.json().get("thread_id") or cr.json().get("id", "")
        if tid:
            r = client.get(f"{BASE}/echo/threads/{tid}/summary")
            assert r.status_code == 200

    def test_get_nonexistent_thread_404(self, client):
        r = client.get(f"{BASE}/echo/threads/no-such-thread-id-xyz")
        assert r.status_code == 404

    def test_threads_no_store_returns_503_or_empty(self, client_no_store):
        r = client_no_store.get(f"{BASE}/echo/threads")
        assert r.status_code in (200, 503)

    def test_thread_list_with_user_filter(self, client):
        r = client.get(f"{BASE}/echo/threads?user_id=filterme")
        assert r.status_code == 200

    def test_full_thread_lifecycle(self, client):
        """Create → chat (persist) → get messages → clear → delete."""
        # 1. Chat to produce a turn
        chat_r = client.post(
            f"{BASE}/echo/chat",
            json={
                "content": "lifecycle test",
                "thread_id": "lifecycle-001",
                "persist": True,
            },
        )
        assert chat_r.status_code == 200

        # 2. Get messages
        msgs_r = client.get(f"{BASE}/echo/threads/lifecycle-001/messages")
        assert msgs_r.status_code == 200

        # 3. Clear messages
        clear_r = client.delete(f"{BASE}/echo/threads/lifecycle-001/messages")
        assert clear_r.status_code == 200

        # 4. Delete thread
        del_r = client.delete(f"{BASE}/echo/threads/lifecycle-001")
        assert del_r.status_code == 200


