class TestFeedback:
    def test_submit_feedback_200(self, client):
        r = client.post(
            f"{BASE}/echo/feedback",
            json={
                "query": "what is agentomatic?",
                "response": "It is a platform.",
                "rating": 5,
                "user_id": "test-user",
            },
        )
        assert r.status_code == 200

    def test_submit_thumbs_up(self, client):
        r = client.post(
            f"{BASE}/echo/feedback",
            json={
                "query": "q",
                "response": "r",
                "rating": 1,
            },
        )
        assert r.status_code == 200

    def test_submit_thumbs_down_with_correction(self, client):
        # rating must be 1-5 (ge=1, le=5) per FeedbackRequest schema
        r = client.post(
            f"{BASE}/echo/feedback",
            json={
                "query": "q",
                "response": "r",
                "rating": 1,
                "correction": "The correct answer is X",
                "comment": "Response was wrong",
                "feedback_type": "correction",
            },
        )
        assert r.status_code == 200

    def test_list_feedback_200(self, client):
        # Submit one first
        client.post(f"{BASE}/echo/feedback", json={"query": "q", "response": "r", "rating": 1})
        r = client.get(f"{BASE}/echo/feedback")
        assert r.status_code == 200

    def test_export_feedback_200(self, client):
        r = client.get(f"{BASE}/echo/feedback/export")
        assert r.status_code == 200

    def test_class_agent_feedback(self, client):
        r = client.post(
            f"{BASE}/class_echo/feedback",
            json={
                "query": "q",
                "response": "r",
                "rating": 5,
            },
        )
        assert r.status_code == 200


# ===========================================================================
# 13. Studio endpoints
# ===========================================================================


class TestStudioEndpoints:
    def test_studio_run_stream_functional(self, client):
        """Studio stream for a node_fn agent: 200 + [DONE] sentinel.

        Studio is designed for graph agents (graph_fn); node_fn agents
        emit a run_error event in the stream but the HTTP status is still
        200 and the stream closes cleanly with [DONE].
        """
        r = client.post("/studio/agents/echo/runs/stream", json={"query": "studio"})
        assert r.status_code in (200, 404)
        if r.status_code == 200:
            # Stream must close cleanly — [DONE] must appear
            assert "[DONE]" in r.text

    def test_studio_run_stream_class_agent(self, client):
        r = client.post("/studio/agents/class_echo/runs/stream", json={"query": "studio class"})
        assert r.status_code in (200, 404)
        if r.status_code == 200:
            assert "run_error" not in r.text

    def test_studio_graph_endpoint(self, client):
        r = client.get("/studio/agents/class_echo/graph")
        assert r.status_code in (200, 404)


