# 15. Programmatic registration + multi-agent isolation
# ===========================================================================


class TestProgrammaticRegistration:
    def test_register_two_agents_isolated(self):
        p = AgentPlatform(agents_dir="/tmp/_ep_iso", enable_studio=False)

        async def agent_a(state):
            return {"response": "A"}

        async def agent_b(state):
            return {"response": "B"}

        p.register_agent(manifest=AgentManifest(name="agent_a", slug="agent-a"), node_fn=agent_a)
        p.register_agent(manifest=AgentManifest(name="agent_b", slug="agent-b"), node_fn=agent_b)
        app = p.build()

        with TestClient(app) as c:
            ra = c.post(f"{BASE}/agent_a/invoke", json={"query": "?"})
            rb = c.post(f"{BASE}/agent_b/invoke", json={"query": "?"})
            assert ra.json()["response"] == "A"
            assert rb.json()["response"] == "B"

    def test_custom_prefix(self):
        p = AgentPlatform(
            agents_dir="/tmp/_ep_pfx",
            enable_studio=False,
            api_prefix="/custom/v2",
        )

        async def fn(state):
            return {"response": "custom"}

        p.register_agent(manifest=AgentManifest(name="myagent", slug="myagent-slug"), node_fn=fn)
        app = p.build()
        with TestClient(app) as c:
            r = c.post("/custom/v2/myagent/invoke", json={"query": "q"})
            assert r.status_code == 200
            assert r.json()["response"] == "custom"


