class TestResponseShape:
    CANONICAL_FIELDS = {
        "response",
        "agent_type",
        "duration_ms",
        "metadata",
        "suggestions",
        "citations",
        "steps_taken",
    }

    def test_invoke_canonical_fields(self, client):
        data = _invoke(client, "echo").json()
        for f in self.CANONICAL_FIELDS:
            assert f in data, f"missing canonical field: {f}"

    def test_suggestions_is_list(self, client):
        data = _invoke(client, "echo").json()
        assert isinstance(data["suggestions"], list)

    def test_citations_is_list(self, client):
        data = _invoke(client, "echo").json()
        assert isinstance(data["citations"], list)

    def test_steps_taken_is_list(self, client):
        data = _invoke(client, "echo").json()
        assert isinstance(data["steps_taken"], list)

    def test_metadata_is_dict(self, client):
        data = _invoke(client, "echo").json()
        assert isinstance(data["metadata"], dict)

    def test_class_agent_canonical_fields(self, client):
        data = _invoke(client, "class_echo", "fields").json()
        assert "response" in data


