# 17. Lifecycle hooks
# ===========================================================================


class TestLifecycleHooks:
    def test_before_after_node_hooks_called(self):
        p = AgentPlatform(agents_dir="/tmp/_hooks", enable_studio=False)
        before_calls: list[str] = []
        after_calls: list[str] = []

        async def fn(state):
            return {"response": "hooked"}

        p.register_agent(
            manifest=AgentManifest(name="hooked_agent", slug="hooked-agent"),
            node_fn=fn,
        )
        # Use the correct hook registration methods
        p.register_before_node_hook(lambda name, state: before_calls.append(name))
        p.register_after_node_hook(lambda name, result: after_calls.append(name))
        app = p.build()

        with TestClient(app) as c:
            c.post(f"{BASE}/hooked_agent/invoke", json={"query": "hook"})

        assert "hooked_agent" in before_calls
        assert "hooked_agent" in after_calls
